s.srcdoc="    <!DOCTYPE html>\n    <body>\n        "+('<iframe id="player" type="text/html" style="position:absolute; top:0px; left:0px; bottom:0px; right:10px; width:100%; height:100%; border:none; margin:0; padding:0; overflow:hidden; z-index:999999;" src="'+A.bfn("https","www.youtube.com","embed/"+r.a,q).l(0)+'" frameborder="0" allowfullscreen></iframe>')+"\n        <script>\n            var tag = document.createElement('script');\ntag.src = \"https://www.youtube.com/iframe_api\";\nvar firstScriptTag = document.getElementsByTagName('script')[0];\nfirstScriptTag.parentNode.insertBefore(tag, firstScriptTag);\n\n            var player;\n            var timerId;\n            function onYouTubeIframeAPIReady() {\n                player = new YT.Player('player', {\n                    events: {\n                      onReady: (event) => sendMessage({ 'Ready': true }),\n                      onStateChange: (event) => sendPlayerStateChange(event.data),\n                      onPlaybackQualityChange: (event) => sendMessage({ 'PlaybackQualityChange': event.data }),\n                      onPlaybackRateChange: (event) => sendMessage({ 'PlaybackRateChange': event.data }),\n                      onError: (error) => sendMessage({ 'Errors': event.data }),\n                    },\n                });\n            }\n            \n            window.addEventListener('message', (event) => {\n               try { eval(event.data) } catch (e) {}\n            }, false);\n            \n            function sendMessage(message) {\n              window.parent.postMessage(JSON.stringify(message), '*');\n            }\n\n            function sendPlayerStateChange(playerState) {\n                clearTimeout(timerId);\n                sendMessage({ 'StateChange': playerState });\n                if (playerState == 1) {\n                    startSendCurrentTimeInterval();\n                    sendVideoData(player);\n                }\n            }\n\n            function sendVideoData(player) {\n                var videoData = {\n                    'duration': player.getDuration(),\n                    'title': player.getVideoData().title,\n                    'author': player.getVideoData().author,\n                    'videoId': player.getVideoData().video_id\n                };\n                sendMessage({ 'VideoData': videoData });\n            }\n\n            function startSendCurrentTimeInterval() {\n                timerId = setInterval(function () {\n                  var videoTime = {\n                      'currentTime': player.getCurrentTime(),\n                      'videoLoadedFraction': player.getVideoLoadedFraction()\n                  };\n                  sendMessage({ 'VideoTime': videoTime });\n                }, 100);\n            }\n            \n            function play() {\n  player.playVideo();\n  return '';\n}\nfunction pause() {\n  player.pauseVideo();\n  return '';\n}\nfunction loadById(loadSettings) {\n  player.loadVideoById(loadSettings);\n  return '';\n}\nfunction cueById(cueSettings) {\n  player.cueVideoById(cueSettings);\n  return '';\n}\nfunction loadPlaylist(loadSettings) {\n  player.loadPlaylist(loadSettings);\n  return '';\n}\nfunction cuePlaylist(loadSettings) {\n  player.cuePlaylist(loadSettings);\n  return '';\n}\nfunction mute() {\n  player.mute();\n  return '';\n}\nfunction unMute() {\n  player.unMute();\n  return '';\n}\nfunction setVolume(volume) {\n  player.setVolume(volume);\n  return '';\n}\nfunction seekTo(position, seekAhead) {\n  player.seekTo(position, seekAhead);\n  return '';\n}\nfunction setSize(width, height) {\n  player.setSize(width, height);\n  return '';\n}\nfunction setPlaybackRate(rate) {\n  player.setPlaybackRate(rate);\n  return '';\n}\nfunction setLoop(loopPlaylists) {\n  player.setLoop(loopPlaylists);\n  return '';\n}\nfunction setShuffle(shufflePlaylist) {\n  player.setShuffle(shufflePlaylist);\n  return '';\n}\nfunction previous() {\n  player.previousVideo();\n  return '';\n}\nfunction next() {\n  player.nextVideo();\n  return '';\n}\nfunction playVideoAt(index) {\n  player.playVideoAt(index);\n  return '';\n}\nfunction stop() {\n  player.stopVideo();\n  return '';\n}\nfunction isMuted() {\n  return player.isMuted();\n}\nfunction hideTopMenu() {\n  try { document.querySelector('#player').contentDocument.querySelector('.ytp-chrome-top').style.display = 'none'; } catch(e) { }\n  return '';\n}\nfunction hidePauseOverlay() {\n  try { document.querySelector('#player').contentDocument.querySelector('.ytp-pause-overlay').style.display = 'none'; } catch(e) { }\n  return '';\n}\n\n        </script>\n    </body>\n  "
